SELECT [DDT_Picking Header].[Location Code], IIf([DDT_Picking line.location code]="PMAG","CELM01.BIDONE","CELM02.BIDONE") AS [bin code], [DDT_Picking Line].No_ AS [iTEM NO_], "" AS [Variant Code], "PA" AS [Unit of Measure Code], "STOCK" AS [Zone code], "STOCC-PREL" AS [bin Type Code], "" AS [Warehouse Class Code], 0 AS [Block Movment], 0 AS [Min_ Qty_], 0 AS [Max_ Qty_], 0 AS [Bin Ranking], 0 AS Fixed, 0 AS [Cross_Dock Bin], 0 AS [Default], 1 AS [Qty_ Per Unit of Measure], 0 AS Dedicated, [DDT_Picking Line].[Model Item No_]
FROM [DDT_Picking Line] INNER JOIN [DDT_Picking Header] ON ([DDT_Picking Line].[Document No_] = [DDT_Picking Header].No_) AND ([DDT_Picking Line].[Document Type] = [DDT_Picking Header].[Document Type])
GROUP BY [DDT_Picking Header].[Location Code], IIf([DDT_Picking line.location code]="PMAG","CELM01.BIDONE","CELM02.BIDONE"), [DDT_Picking Line].No_, "PA", "STOCK", "STOCC-PREL", "", 1, 0, [DDT_Picking Line].[Model Item No_], "", 0, 0, 0, 0, 0, 0, 0, [DDT_Picking Header].No_, [DDT_Picking Line].Type
HAVING ((([DDT_Picking Header].No_)="SPD-25/06501" Or ([DDT_Picking Header].No_)="SPD-25/06502" Or ([DDT_Picking Header].No_)="SPD-25/06507" Or ([DDT_Picking Header].No_)="SPD-25/06550" Or ([DDT_Picking Header].No_)="SPD-25/06552" Or ([DDT_Picking Header].No_)="SPD-25/06560" Or ([DDT_Picking Header].No_)="SPD-25/06568" Or ([DDT_Picking Header].No_)="SPD-25/06565" Or ([DDT_Picking Header].No_)="SPD-25/06569" Or ([DDT_Picking Header].No_)="SPD-25/07740" Or ([DDT_Picking Header].No_)="SPD-25/07751" Or ([DDT_Picking Header].No_)="SPD-25/07752" Or ([DDT_Picking Header].No_)="SPD-25/07753" Or ([DDT_Picking Header].No_)="SPD-25/06499" Or ([DDT_Picking Header].No_)="SPD-25/06570" Or ([DDT_Picking Header].No_)="SPD-25/06509" Or ([DDT_Picking Header].No_)="SPD-25/06526") AND (([DDT_Picking Line].Type)=20));

